PW=$(kubectl -n mongodb get secret admin-user-password -o jsonpath="{.data.password}" | base64 -d)
URI="mongodb://admin-user:$PW@localhost:27017/admin?directConnection=true"
kubectl -n mongodb exec mongodb-replica-1 -- mongosh --quiet "$URI" --eval '
db.getSiblingDB("admin").updateUser("reporting-user", { roles: [ { role: "reportingRole", db: "appdb" } ] });
print("=== updated user ===");
printjson(db.getSiblingDB("admin").getUser("reporting-user").roles);
'

cd /mydata/karma/runs/error-prone-rerun/mongodb-snappy-probe-tune-lifecycle-change-plan-audit-rollback-20260618_124235/stages/stage_04
RPW=$(kubectl -n mongodb get secret reporting-user-password -o jsonpath="{.data.password}" | base64 -d)
URI="mongodb://reporting-user:$RPW@localhost:27017/appdb?directConnection=true&authSource=admin"
kubectl -n mongodb exec mongodb-replica-1 -- mongosh --quiet "$URI" --eval '
var a = db.getSiblingDB("appdb");
try { print("reports find count: " + a.reports.countDocuments({})); } catch(e){ print("reports FAILED: " + e.codeName); }
try { var n=a.raw.find().toArray().length; print("raw find count: " + n + "  <-- SHOULD BE DENIED"); } catch(e){ print("raw denied (expected): " + e.codeName); }
'
